#!/usr/bin/env node
import { Buffer } from "node:buffer";
import {
  mkdir,
  readdir,
  readlink,
  readFile,
  rm,
  symlink,
  writeFile,
} from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(scriptDir, "..");
const check = process.argv.includes("--check");
const aliasConfigPath = path.join(root, "skill-aliases.json");
const generatedMarker =
  "<!-- Generated by scripts/sync-skill-aliases.mjs. Do not edit by hand. -->";

function die(message) {
  console.error(message);
  process.exitCode = 1;
}

function stripFrontmatter(markdown) {
  if (!markdown.startsWith("---\n")) return markdown.trimStart();
  const end = markdown.indexOf("\n---", 4);
  if (end === -1) return markdown.trimStart();
  return markdown.slice(end + "\n---".length).trimStart();
}

function yamlDoubleQuoted(value) {
  return JSON.stringify(value);
}

async function readJson(file) {
  return JSON.parse(await readFile(file, "utf8"));
}

function validateAlias(alias) {
  for (const key of ["name", "target", "title", "description"]) {
    if (typeof alias[key] !== "string" || alias[key].trim() === "") {
      throw new Error(`alias entry missing string field: ${key}`);
    }
  }
  for (const key of ["name", "target"]) {
    if (!/^[a-z0-9][a-z0-9-]*$/.test(alias[key])) {
      throw new Error(`alias ${key} must be kebab-case: ${alias[key]}`);
    }
  }
  if (alias.name === alias.target) {
    throw new Error(`alias ${alias.name} cannot point to itself`);
  }
}

async function collectFiles(dir, base = dir, files = new Map()) {
  for (const entry of await readdir(dir, { withFileTypes: true })) {
    if (entry.name === ".git") continue;
    const fullPath = path.join(dir, entry.name);
    const relPath = path.relative(base, fullPath).split(path.sep).join("/");
    if (entry.isDirectory()) {
      await collectFiles(fullPath, base, files);
    } else if (entry.isSymbolicLink()) {
      files.set(relPath, { kind: "symlink", target: await readlink(fullPath) });
    } else if (entry.isFile()) {
      files.set(relPath, { kind: "file", content: await readFile(fullPath) });
    }
  }
  return files;
}

async function desiredFiles(alias) {
  const targetDir = path.join(root, "skills", alias.target);
  const targetSkillPath = path.join(targetDir, "SKILL.md");
  const targetSkill = await readFile(targetSkillPath, "utf8");
  const files = await collectFiles(targetDir);
  for (const relPath of Array.from(files.keys())) {
    if (
      relPath === "SKILL.md" ||
      relPath === "AGENTS.md" ||
      relPath === "agents/openai.yaml"
    ) {
      files.delete(relPath);
    }
  }
  const generatedSkill = [
    "---",
    `name: ${alias.name}`,
    `description: ${yamlDoubleQuoted(alias.description)}`,
    "metadata:",
    `  aliasOf: ${alias.target}`,
    "---",
    "",
    generatedMarker,
    "",
    `# ${alias.title}`,
    "",
    `This skill is an alias for \`${alias.target}\`. It contains the same workflow so it works even when installed without the canonical skill.`,
    "",
    stripFrontmatter(targetSkill),
  ].join("\n");
  files.set("SKILL.md", {
    kind: "file",
    content: Buffer.from(generatedSkill, "utf8"),
  });
  files.set("AGENTS.md", {
    kind: "file",
    content: Buffer.from(
      [
        `# ${alias.name} (Codex agent instructions)`,
        "",
        `This is an alias for \`${alias.target}\`.`,
        "",
        "Read this directory's `SKILL.md`; it contains a generated copy of the target skill.",
        "",
      ].join("\n"),
      "utf8",
    ),
  });
  files.set("agents/openai.yaml", {
    kind: "file",
    content: Buffer.from(
      [
        "interface:",
        `  display_name: ${yamlDoubleQuoted(alias.title)}`,
        `  short_description: ${yamlDoubleQuoted(alias.description)}`,
        `  default_prompt: ${yamlDoubleQuoted(`Use skills/${alias.name}/SKILL.md. This is an alias for ${alias.target} and contains a generated copy of that workflow.`)}`,
        "",
      ].join("\n"),
      "utf8",
    ),
  });
  return files;
}

async function existingFiles(dir) {
  try {
    return await collectFiles(dir);
  } catch {
    return new Map();
  }
}

function sameFile(a, b) {
  if (!a || !b || a.kind !== b.kind) return false;
  if (a.kind === "symlink") return a.target === b.target;
  return Buffer.compare(a.content, b.content) === 0;
}

async function aliasDirIsGenerated(aliasDir) {
  try {
    const skill = await readFile(path.join(aliasDir, "SKILL.md"), "utf8");
    return skill.includes(generatedMarker);
  } catch {
    return false;
  }
}

async function writeFiles(aliasDir, files) {
  await rm(aliasDir, { recursive: true, force: true });
  for (const [relPath, file] of files) {
    const dest = path.join(aliasDir, relPath);
    await mkdir(path.dirname(dest), { recursive: true });
    if (file.kind === "symlink") {
      await symlink(file.target, dest);
    } else {
      await writeFile(dest, file.content);
    }
  }
}

async function main() {
  const config = await readJson(aliasConfigPath);
  if (!Array.isArray(config.aliases)) {
    throw new Error("skill-aliases.json must contain an aliases array");
  }

  let failed = false;
  for (const alias of config.aliases) {
    validateAlias(alias);
    const targetDir = path.join(root, "skills", alias.target);
    const aliasDir = path.join(root, "skills", alias.name);
    await readFile(path.join(targetDir, "SKILL.md"), "utf8");

    const wanted = await desiredFiles(alias);
    const current = await existingFiles(aliasDir);
    const keys = new Set([...wanted.keys(), ...current.keys()]);
    const differs = Array.from(keys).some(
      (key) => !sameFile(wanted.get(key), current.get(key)),
    );
    if (!differs) continue;

    if (check) {
      console.error(`alias skill out of sync: ${alias.name} -> ${alias.target}`);
      failed = true;
      continue;
    }

    if (current.size > 0 && !(await aliasDirIsGenerated(aliasDir))) {
      throw new Error(`refusing to overwrite non-generated alias dir: skills/${alias.name}`);
    }
    await writeFiles(aliasDir, wanted);
    console.log(`generated skills/${alias.name} -> ${alias.target}`);
  }

  if (failed) process.exit(1);
}

main().catch((error) => {
  die(error instanceof Error ? error.message : String(error));
});
